import boto3
import json

# 1. Create a Lambda function that serves as a tool handler
# (deploy separately; this shows the Bedrock agent setup)

bedrock_agent = boto3.client("bedrock-agent", region_name="us-east-1")

# 2. Create the agent
response = bedrock_agent.create_agent(
    agentName="customer-support-agent",
    agentResourceRoleArn="arn:aws:iam::123456789012:role/BedrockAgentRole",
    foundationModel="anthropic.claude-3-5-sonnet-20241022-v2:0",
    instruction=(
        "You are a customer support agent for an e-commerce platform. "
        "Use the provided tools to look up order status, process refunds, "
        "and escalate issues to human agents when needed."
    ),
    idleSessionTTLInSeconds=1800,
)
agent_id = response["agent"]["agentId"]
print(f"Agent created: {agent_id}")

# 3. Register an action group (tool set) backed by a Lambda function
bedrock_agent.create_agent_action_group(
    agentId=agent_id,
    agentVersion="DRAFT",
    actionGroupName="order-tools",
    actionGroupExecutor={
        "lambda": "arn:aws:lambda:us-east-1:123456789012:function:order-tools-handler"
    },
    apiSchema={
        "payload": json.dumps({
            "openapi": "3.0.0",
            "info": {"title": "Order Tools", "version": "1.0"},
            "paths": {
                "/get-order-status": {
                    "get": {
                        "description": "Get the current status of an order by order ID",
                        "parameters": [{
                            "name": "orderId",
                            "in": "query",
                            "required": True,
                            "schema": {"type": "string"}
                        }],
                        "responses": {"200": {"description": "Order status"}}
                    }
                }
            }
        })
    },
)

# 4. Prepare and deploy the agent
bedrock_agent.prepare_agent(agentId=agent_id)

# 5. Create an alias pointing to the deployed version
alias_resp = bedrock_agent.create_agent_alias(
    agentId=agent_id,
    agentAliasName="production",
)
alias_id = alias_resp["agentAlias"]["agentAliasId"]

# 6. Invoke the agent from the runtime client
runtime = boto3.client("bedrock-agent-runtime", region_name="us-east-1")
invoke_resp = runtime.invoke_agent(
    agentId=agent_id,
    agentAliasId=alias_id,
    sessionId="session-001",          # reuse session ID for multi-turn
    inputText="What is the status of order #98765?",
)

# Stream the response
for event in invoke_resp["completion"]:
    if "chunk" in event:
        chunk_text = event["chunk"]["bytes"].decode("utf-8")
        print(chunk_text, end="", flush=True)
